import React from 'react';

/**
 * Hero component - Main hero section with title and subtitle
 * @param {Object} props - Component props
 * @param {string} props.title - Main hero title
 * @param {string} props.subtitle - Hero subtitle/description
 */
const Hero = ({ 
  title = "PlanWise", 
  subtitle = "Smart leave planning that saves you time and money. Track holidays, plan vacations, and discover long weekends with AI-powered insights." 
}) => {
  return (
    <div className="bg-gradient-to-br from-purple-50 to-pink-50 py-20">
      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-16">
          <h1 className="text-5xl md:text-6xl font-bold mb-6" style={{color: '#581c87'}}>
            {title}
          </h1>
          <p className="text-xl mb-12 max-w-3xl mx-auto" style={{color: '#1F2937'}}>
            {subtitle}
          </p>
        </div>
      </div>
    </div>
  );
};

export default Hero;
